-- Eliminar principios activos L01 de administración exclusivamente oral.
-- Verificado contra viasAdministracion de CIMA (abril 2026).
DELETE FROM principio_activo
WHERE dci IN ('Fedratinib', 'abemaciclib', 'acalabrutinib', 'afatinib', 'alectinib', 'alpelisib', 'aminolevulinato de metilo', 'anagrelida', 'asciminib', 'avapritinib', 'axitinib', 'belzutifán', 'bexaroteno', 'binimetinib', 'bosutinib', 'brigatinib', 'busulfano', 'cabozantinib', 'capecitabina', 'capivasertib', 'capmatinib', 'ceritinib', 'clorambucilo', 'clormetina', 'cobimetinib', 'crizotinib', 'dabrafenib', 'dacomitinib', 'dasatinib', 'decitabina + cedazuridina', 'encorafenib', 'entrectinib', 'erdafitinib', 'erlotinib', 'estramustina', 'everolimus', 'fluorouracilo + ácido salicílico', 'fruquintinib', 'futibatinib', 'gefitinib', 'gilteritinib', 'glasdegib', 'hidroxicarbamida', 'ibrutinib', 'idelalisib', 'imatinib', 'inavolisib', 'ivosidenib', 'ixazomib', 'lapatinib', 'larotrectinib', 'lazertinib', 'lenvatinib', 'lomustina', 'lorlatinib', 'melfalán', 'mercaptopurina', 'midostaurina', 'mirdametinib', 'mitotano', 'momelotinib', 'neratinib', 'nilotinib', 'nintedanib', 'niraparib', 'niraparib + abiraterona', 'nirogacestat', 'olaparib', 'osimertinib', 'palbociclib', 'panobinostat', 'pazopanib', 'pemigatinib', 'pirtobrutinib', 'ponatinib', 'pralsetinib', 'procarbazina', 'quizartinib', 'regorafenib', 'ribociclib', 'ripretinib', 'rucaparib', 'ruxolitinib', 'selinexor', 'selpercatinib', 'selumetinib', 'sonidegib', 'sorafenib', 'sotorasib', 'sunitinib', 'talazoparib', 'talimogén laherparepvec', 'tegafur', 'tegafur + gimeracilo + oteracilo', 'temozolomida', 'tepotinib', 'tioguanina', 'tivozanib', 'topotecán', 'trametinib', 'tretinoína', 'trifluridina + tipiracilo', 'tucatinib', 'vandetanib', 'vemurafenib', 'venetoclax', 'vimseltinib', 'vinorelbina', 'vismodegib', 'vorasidenib', 'zanubrutinib', 'ácido 5-aminolevulínico')
  AND (SELECT count(*) FROM presentacion_comercial WHERE principio_activo_id = principio_activo.id) = 0;
